SELECT date, SUM(volume) AS total_volume
FROM trading_volumes
WHERE date = '2023-01-01';

SELECT ticker_id, open, close
FROM daily_quotes
WHERE date = '2023-04-01';

SELECT MAX(close) AS highest_close_price
FROM daily_quotes
WHERE ticker_id = 123 AND date = '2023-04-01';

SELECT AVG(close) AS average_closing_price
FROM daily_quotes
WHERE date = '2023-09-01';

SELECT AVG(volume) AS avg_volume
FROM daily_quotes
WHERE ticker_id = (SELECT ticker_id FROM tickers WHERE ticker_symbol = 'AAPL');

SELECT date, ticker_id, high, MAX(high) OVER (PARTITION BY date) as max_high_of_day
FROM daily_quotes
ORDER BY date, ticker_id;
